import{_ as l,o as a,c as o,a2 as i}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Codex Practices","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/tooling/codex.md","filePath":"ai-native/tooling/codex.md"}'),r={name:"ai-native/tooling/codex.md"};function t(d,e,n,c,s,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="codex-practices" tabindex="-1">Codex Practices <a class="header-anchor" href="#codex-practices" aria-label="Permalink to &quot;Codex Practices&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p><strong>最后核对：2026-06-15</strong></p><p>本指南适用于 Codex CLI、IDE Extension 和 Codex App。具体能力以 OpenAI 官方文档为准。</p><h2 id="推荐实践" tabindex="-1">推荐实践 <a class="header-anchor" href="#推荐实践" aria-label="Permalink to &quot;推荐实践&quot;">​</a></h2><h3 id="_1-用四个字段定义任务" tabindex="-1">1. 用四个字段定义任务 <a class="header-anchor" href="#_1-用四个字段定义任务" aria-label="Permalink to &quot;1. 用四个字段定义任务&quot;">​</a></h3><p>一个可执行任务至少说明：</p><ul><li><code>Goal</code>：要改变什么</li><li><code>Context</code>：相关文件、错误、文档和示例</li><li><code>Constraints</code>：架构、安全和范围限制</li><li><code>Done when</code>：测试、行为或交付物达到什么条件</li></ul><p>完成条件应尽量由命令、测试、截图或可检查文件验证。</p><h3 id="_2-只为复杂任务先计划" tabindex="-1">2. 只为复杂任务先计划 <a class="header-anchor" href="#_2-只为复杂任务先计划" aria-label="Permalink to &quot;2. 只为复杂任务先计划&quot;">​</a></h3><p>跨模块修改、模糊需求和高风险迁移先使用 Plan mode。范围清楚的小修改直接执行，避免让流程成本大于任务本身。</p><h3 id="_3-用-agents-md-保存仓库规则" tabindex="-1">3. 用 <code>AGENTS.md</code> 保存仓库规则 <a class="header-anchor" href="#_3-用-agents-md-保存仓库规则" aria-label="Permalink to &quot;3. 用 `AGENTS.md` 保存仓库规则&quot;">​</a></h3><p><code>AGENTS.md</code> 应包含：</p><ul><li>仓库结构和关键目录</li><li>构建、测试、Lint 和格式化命令</li><li>本项目特有的工程约束</li><li>禁止事项、权限边界和完成标准</li></ul><p>根目录保存共享规则，子目录只添加局部差异。离当前工作目录更近的规则更具体，不应在多个层级复制同一正文。</p><p>当同一错误重复出现时，先做复盘，再决定是否更新 <code>AGENTS.md</code>。不要把一次性偏好永久写入仓库规则。</p><h3 id="_4-分离个人配置与项目配置" tabindex="-1">4. 分离个人配置与项目配置 <a class="header-anchor" href="#_4-分离个人配置与项目配置" aria-label="Permalink to &quot;4. 分离个人配置与项目配置&quot;">​</a></h3><ul><li><code>~/.codex/config.toml</code>：个人默认值和跨项目工具</li><li><code>.codex/config.toml</code>：可信仓库的项目配置</li><li>命令行参数：一次性覆盖</li></ul><p>项目配置不应包含个人凭证。模型、推理强度、Sandbox、Approval、MCP 和 Hook 应按作用域放置。</p><h3 id="_5-用-skill-承载可复用工作流" tabindex="-1">5. 用 Skill 承载可复用工作流 <a class="header-anchor" href="#_5-用-skill-承载可复用工作流" aria-label="Permalink to &quot;5. 用 Skill 承载可复用工作流&quot;">​</a></h3><p>满足以下条件时再创建 Skill：</p><ul><li>有明确触发场景和输出</li><li>已重复执行，步骤相对稳定</li><li>需要引用模板、脚本或领域资料</li></ul><p>Skill 应聚焦一个任务，描述中写清适用和不适用边界。优先使用指令；只有需要确定性或外部工具时才增加脚本。</p><h3 id="_6-用-mcp-连接实时外部系统" tabindex="-1">6. 用 MCP 连接实时外部系统 <a class="header-anchor" href="#_6-用-mcp-连接实时外部系统" aria-label="Permalink to &quot;6. 用 MCP 连接实时外部系统&quot;">​</a></h3><p>需要访问文档、Issue、设计稿、监控或数据库时，优先使用经过授权的 MCP，而不是把旧数据复制进 Prompt。</p><p>配置时：</p><ul><li>只启用任务需要的 Server 和 Tool</li><li>Token 通过环境变量或 OAuth 注入</li><li>高风险 Tool 保持 <code>prompt</code> 审批</li><li>为启动和调用设置合理超时</li><li>将跨 Tool 的限制写进 MCP Server instructions</li></ul><h3 id="_7-用-hook-和-rules-执行确定性约束" tabindex="-1">7. 用 Hook 和 Rules 执行确定性约束 <a class="header-anchor" href="#_7-用-hook-和-rules-执行确定性约束" aria-label="Permalink to &quot;7. 用 Hook 和 Rules 执行确定性约束&quot;">​</a></h3><p>适合 Hook 或 Rules 的内容包括：</p><ul><li>密钥扫描</li><li>修改后的格式化或测试</li><li>禁止危险命令</li><li>Stop 前的验证门禁</li></ul><p>Hook 是代码，应审查来源和变更。不要用 Hook 代替所有判断，也不要为方便配置过宽的命令前缀。</p><h3 id="_8-把验证和审查放进完成条件" tabindex="-1">8. 把验证和审查放进完成条件 <a class="header-anchor" href="#_8-把验证和审查放进完成条件" aria-label="Permalink to &quot;8. 把验证和审查放进完成条件&quot;">​</a></h3><p>Codex 完成修改后至少应：</p><ol><li>运行与改动相关的测试或检查。</li><li>阅读结果并修复失败。</li><li>检查 Diff 是否有回归和越界修改。</li><li>汇报实际证据以及未能执行的检查。</li></ol><p>高风险改动使用独立线程或新上下文做第二次 Review，避免实现者自我确认。</p><h2 id="不推荐" tabindex="-1">不推荐 <a class="header-anchor" href="#不推荐" aria-label="Permalink to &quot;不推荐&quot;">​</a></h2><ul><li>用一个超长 <code>AGENTS.md</code> 装下全部知识</li><li>将可从代码推断的信息重复写入指令</li><li>默认授予整个文件系统或网络访问</li><li>把一次成功的 Prompt 直接升级为组织标准</li><li>未运行验证就让 Agent 自行判断任务完成</li><li>在多个宿主中复制并长期维护同一 Skill 正文</li></ul><h2 id="采用清单" tabindex="-1">采用清单 <a class="header-anchor" href="#采用清单" aria-label="Permalink to &quot;采用清单&quot;">​</a></h2><ul><li>[ ] 根目录存在短而准确的 <code>AGENTS.md</code></li><li>[ ] 关键命令可由 Agent 直接执行</li><li>[ ] 完成条件包含机器可读的验证</li><li>[ ] 项目配置不含凭证</li><li>[ ] MCP 和命令权限遵循最小授权</li><li>[ ] 重复工作已评估是否应进入 Skill</li><li>[ ] 强制规则已评估是否应进入 Hook、Rules 或 CI</li></ul><h2 id="官方参考" tabindex="-1">官方参考 <a class="header-anchor" href="#官方参考" aria-label="Permalink to &quot;官方参考&quot;">​</a></h2><ul><li><a href="https://developers.openai.com/codex/learn/best-practices" target="_blank" rel="noreferrer">Codex best practices</a></li><li><a href="https://developers.openai.com/codex/guides/agents-md" target="_blank" rel="noreferrer">Custom instructions with AGENTS.md</a></li><li><a href="https://developers.openai.com/codex/skills" target="_blank" rel="noreferrer">Agent Skills</a></li><li><a href="https://developers.openai.com/codex/mcp" target="_blank" rel="noreferrer">Model Context Protocol</a></li><li><a href="https://developers.openai.com/codex/hooks" target="_blank" rel="noreferrer">Hooks</a></li></ul>',41)])])}const m=l(r,[["render",t]]);export{u as __pageData,m as default};
